// BAD: caller fully controls tx.gasprice, so this gate is meaningless
// require(tx.gasprice <= maxGasPrice, "gas price too high");
// uint256 refund = gasUsed * tx.gasprice; // attacker inflates the refund

// GOOD: remove the dependency and redesign the incentive.
// 1) For refunds/rewards, use a fixed rate set by governance, not the tx price:
uint256 public rewardPerAction; // set by owner/governance

function claim() external {
    payable(msg.sender).transfer(rewardPerAction);
}

// 2) For frontrunning protection, use a commit-reveal scheme instead of a gas price cap:
mapping(address => bytes32) public commits;

function commit(bytes32 hash) external {
    commits[msg.sender] = hash; // keccak256(abi.encode(choice, salt, msg.sender))
}

function reveal(uint256 choice, bytes32 salt) external {
    require(commits[msg.sender] == keccak256(abi.encode(choice, salt, msg.sender)), "bad reveal");
    // act on the committed choice; frontrunners learned nothing at commit time
}
